import{_ as a,o as e,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const A=JSON.parse('{"title":"司书战斗手册","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/司书战斗手册/司书战斗手册.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/司书战斗手册/司书战斗手册.md"}'),s={name:"4.资源分区/6.技艺及称号/通用及综合类/司书战斗手册/司书战斗手册.md"};function o(d,b,_,l,i,c){return e(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"司书战斗手册",tabindex:"-1"},[p("司书战斗手册 "),r("a",{class:"header-anchor",href:"#司书战斗手册","aria-label":'Permalink to "司书战斗手册"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘001A")])])],-1),n('<h1 id="司书战斗手册-1" tabindex="-1">司书战斗手册 <a class="header-anchor" href="#司书战斗手册-1" aria-label="Permalink to &quot;司书战斗手册&quot;">​</a></h1><p>司书战斗手册<br> 司书战斗手册不会为购买者提供属性<br> （D+500/C+1000/B+2000/A+4500/S+8000）<br> 本手册是由“馆”在前往郊区后，一名不知名的总楼层指定司书编写而成的，对于新手司书助理和新的楼层指定司书教学的战斗手册。这本战斗手册购买时立即获得战斗书页系统、光芒系统、情感硬币系统，可花费750奖励点解锁核心书页系统。在手册升级至C级时再获得混乱抗性系统。<br> 然而由于本手册在进入主神空间时资料已经有许多缺失，主神在将其转换为可用资源时进行了些许调整，因此本手册所涉及的战斗系统与书页效果会和原版有些许出入。</p><p>●战斗书页系统<br> 在本手册中记录着多种“馆”曾在L巢使其被使用过的书页，一些是由宾客变化而成的书页中记载着不同的战斗方式；而另一些则是由馆内的异想体所提供的书页，只能使用情感硬币系统才能得以被使用。<br> 战斗书页分为平装（D级/绿色书页）、精装（C级/蓝色书页）、限定（B级/紫色书页）、艺术（A级/金色书页）四个等级，异想体书页与E.G.O书页没有书页等级。<br> 战斗书页中会记载着三种类型骰，分别为进攻型骰子（包括斩击、突刺和打击）、防御型骰子（包括闪避和招架）、反击型骰子，战斗书页中不一定会同时记载这三种骰子。<br> 当司书使用一张记载有进攻型骰子的书页进行攻击时，每有一个进攻型骰子，就需和受击者进行一次拼点，双方各掷一枚六面骰子。若攻击者的点数更高，则拼点成功的进攻型骰子所具有的效果会正常生效，否则只继续进行攻击检定，不拥有额外效果。斩击骰子的伤害类型为挥砍、突刺骰子的伤害类型为穿刺、打击的伤害类型为钝击。若一张书页中有多个不同的进攻型骰子（例如一个打击骰和一个穿刺骰），则这次攻击造成的伤害会平均分配给这些进攻型骰子所对应的伤害性质。<br> 当司书使用一张记载有防御型骰子的书页进行防御时，每有一个防御型骰子，就需和攻击者进行一次拼点，双方各掷一枚六面骰子。若防御者的点数更高，则拼点成功的防御型骰子所具有的效果会正常生效，否则只继续进行对方的攻击检定，不拥有额外效果。招架骰子在成功生效时，会为防御者提供X点格挡；闪避骰子在成功生效时，会让防御者在接下来的这次攻击中至多无视X个成功数。具体效果以书页为准。<br> 书页的对抗检定流程中，无论是哪一方的检定，都不会被全检定加值和全检定附加所影响，不会被其他使数值变动的能力所影响，不会使检定出目被影响。<br> 拼点的成功与失败：当司书使用一张书页进行拼点时，这一书页对应的骰子效果只要因拼点成功而生效，就代表拼点成功；若这一书页的对应的所有骰子均因拼点失败而失效，就意味着拼点失败。<br> 由于手册在编写时，来自于都市之星-杂质的战斗书页遗失过多，记载有反击型骰子的书页已无从考证，因此手册中并没有记录，或许在收集到更多遗失书页的将来，反击型骰子能力也会被记录进来。</p><p>●战斗书页类型<br> 战斗书页共分为四种类型，分别为近战书页、远程书页、范围杀伤书页、装备书页。<br> 远程书页一般具有佚亡能力，被使用过的远程书页会立即移出战斗，在本次舞台战中无法再使用。<br> 范围杀伤书页分为两种类型：交锋和清算。<br> 范围杀伤书页无论如何都会与所有受击者进行拼点，且无论拼点成功与否，都仍然是一次范围攻击。清算类范围杀伤书页在拼点成功时，若受击者以某种形式反击此次攻击，还会再将那种技艺赋予的效果烧毁（仍保留那次反击攻击），被范围杀伤书页击中的角色在这次舞台战中都不能主动应用那种拥有的能力，但他们仍然可以正常使用他们的标准动作和其他能力，这是一个A级心灵来源的支配效果。</p><p>（名词补充：<br> 幕：轮<br> 这一幕：这一轮<br> 舞台：场景<br> 舞台战：战斗场景）</p><p>●核心书页和速度骰系统<br> 750<br> 在获得核心书页时，再额外从历史层/科技层/文学层/艺术层/自然层/语言层/社会层/哲学层/宗教层/总楼层指定司书核心书页中获得一张作为自身的核心书页，这张核心书页初始没有任何效果，仅有6点被动点，当此手册升级为都市传说/都市梦魇/都市之星级时，这个点数将升至8/10/12点，可以购买额外的核心书页以进行“转移被动”，特殊的，因主神空间中并不具备“馆”的能力，因此司书无法装备除艺术书页以外的其他等级非指定司书核心书页，购买的非艺术书页仅能用于转移被动。被转移被动的核心书页的被动能力会占据指定司书核心书页的被动点，当被动点不足时，无法转移大于目前剩余被动点的被动能力。<br> 司书最多只能装备一张书页作为他的核心书页，转移被动后的核心书页不能拥有相同的唯一被动。<br> 同时，核心书页还会提供一枚速度骰子，这枚速度骰子初始有四个面，最大出目为4，最小为1，当掷先攻骰时，这枚速度骰子也会参与，并额外提供出目点数的先攻，一般而言，速度骰不会出现复数，拥有复数速度骰等于拥有额外速度骰数的攻击次数（如：当拥有「速战速决」时），速度骰的面数和最大出目有且仅有可能随着手册内记载的能力而变化，具体由记载的效果决定。<br> 同时，指定层司书只能获得对应层的异想体书页与E.G.O书页，无法获得其他层的对应书页。</p><p>●光芒系统<br> 光芒是大部分战斗书页使用的前提，大部分战斗书页的使用都需要消耗一定数量的光芒。光芒的初始上限为4。<br> 在战斗场景内，光芒在每一幕开始时会自动恢复1点，情感等级提升时会再使光芒上限+1并完全恢复至上限（增加的上限在每一场舞台战结束时自动消失），击杀一名敌对人物也可以恢复1点光芒。<br> 提升上限后的光芒至多不会超过司书的决心+风度，每天以任何方式恢复的光芒总数不能超过司书的决心+风度总数*3。特殊的，光芒无法提升以任何其他非属性提升的形式增加能量池上限</p><p>●混乱抗性系统<br> 混乱抗性基于被受击者生命中的完好，当受击者生命中损失完好时，受击者的混乱抗性会一并被削减。当受击者的混乱抗性完全不存在时（不存在任何完好时），受击者需以意志豁免对那次攻击出目进行一次抵抗，若抵抗失败则进入混乱状态。混乱状态下，人物无法进行任何需要主动行为的动作，失去基本防御，无法闪避和格挡，若人物手中持有物品，他会松手。但混乱状态中的人物保有自我保护的本能，这视为一个A级心灵来源的支配效果。</p><p>●情感硬币系统<br> 司书在战斗过程中会根据战斗的表现而获得情感硬币，遵循以下原则：<br> 拼点成功：获得1枚正面情感硬币<br> 拼点失败：获得1枚负面情感硬币<br> 攻击检定出目大于总期望，且多出三分之一及以上：获得1枚正面情感硬币<br> 攻击检定小于总期望，且只有总期望的三分之一及以下：获得1枚负面情感硬币<br> 舞台战中敌人死亡：获得1枚正面情感硬币<br> 舞台战中队友死亡：获得1枚负面情感硬币<br> 书页能力：获得规定的数目枚情感硬币<br> 司书的初始情感等级为0，情感硬币的累加会让司书的情感等级提升，无论获得的是正面情感硬币还是负面情感硬币，获得足够的情感硬币便可以提升情感等级。<br> 1级：3枚 只会出现D级异想体书页<br> 2级：3枚 会开始出现C级异想体书页<br> 3级：5枚 不再出现D级异想体书页，会开始出现B级异想体书页<br> 4级：7枚 不再出现C级异想体书页，会开始出现A级异想体书页<br> 异想体书页分为觉醒书页和崩溃书页两种，有各自的需求情感硬币组成，如：某崩溃书页需要3枚负面情感硬币才能选择。<br> 每次提升情感等级时，都可以选择一次异想体书页获得，获得后清除拥有的所有情感硬币，并记录等级，每次舞台战结束后，移除所有硬币，归零情感等级。</p><p>D级 都市怪谈<br> “人们在日落之前，没有闲暇去思量，此曲尾声的恐怖。”<br> 此时的“馆”造成了数人死亡或失踪的现象或组织，低阶事务所的主要业务。<br> 解锁传闻级、都市怪谈级战斗书页的获取权，获得司书训练专长。<br> 解锁D级异想体书页获取权。<br> 在“馆”中，司书可以被馆长以馆的能力重塑复活，而在战斗手册中，馆已无法如记录的那样提供能力，而是会在司书进行舞台战时，自动为司书稳定伤势。</p><p>C级 都市传说<br> “嗅到我的屋里，祭物散发的伟大香味。”<br> “馆”已经导致百人以上的死伤与失踪的现象与组织，此类委托对象已经引起了协会方面的注意（尤其是负责治安维护的Zwei协会），是低阶与中阶事务所的主要业务目标。<br> 解锁都市传说级战斗书页的获取权<br> 解锁C级异想体书页获取权。<br> 司书在使用战斗书页时，还会再额外获得1点书页提供的武器伤害。<br> 解锁混乱抗性系统。</p><p>B级 都市恶疾<br> “他们竟说我健康无恙。”<br> “馆”已经导致千人以上的死伤与失踪的现象与组织，此类委托对象可以被各协会中的三科四科或中阶事务所比较成功的处理。<br> 解锁都市恶疾级战斗书页的获取权，<br> 解锁B级异想体书页获取权。<br> 每幕仅一次，司书在使用一张战斗书页前可以向任意一个敌对人物的方向移动不超过其移动距离的米数，若那一幕中，司书使用了带有格挡骰子的书页，则可以选择再获得等同于（专注技能等级+专注：书页专业等级）/2的偏斜防御，还会再获得B6A8S10点偏斜防御，这个效果会消耗司书原本拥有的移动动作，这相当于进行了一次格挡，意味着在这一幕，你无法再进行格挡<br> 在此阶段中，司书已掌握了多种不同能力书页的使用方式，而这些能力也提升了司书对于战斗书页的应用技术。司书每拥有三张带有特殊关键词的平装及以上的战斗书页，便获得在使用拥有特殊关键词，且它们符合条件的战斗书页时的2点附加成功。<br> 特殊关键词包括：燃烧、流血、独一、烟气、充能、卦象、剧目、乐章等。</p><p>A级 都市梦魇<br> “梦破碎了，塔坍塌了。”<br> “馆”已经导致万人以上死伤与失踪的现象与组织(或已牵扯翼公司方面利益)，此类委托对象应交由各协会一科人员或高阶事务所处理。 该等级的存在可能己拥有进行较大规模战役的势力。会对整个区域产生影响。<br> 解锁都市梦魇级战斗书页的获取权。<br> 解锁A级异想体书页获取权。<br> 并解锁艺术级核心书页获取权，从已揭示的艺术级核心书页中选取一张直接获得。</p><p>S级 都市之星（目前并未开放）<br> “我每数一颗星星便呼唤一句美丽的话语。”<br> 极难被处理的委托,经常是触及翼公司核心利益的事务，或势力覆盖一片后巷至数座巢的危险组织(也有可能是造成百万人以上死伤与失踪的重大灾害)，会对整个都市的秩序产生影响，需要Hana协会的分配专门科室负责跟踪走向。此类委托应交由色彩级收尾人或实力较强的一阶事务所处理。</p><p>SS级 杂质（目前并未开放）<br> “我还活着，只是为了找到失落之物。”<br> 对于人类未来发展具有威胁的存在。此评级的事物不再会是任何协会和收尾人事务所的业务目标。此评级的事物只存在于A、B、C公司（首脑、眼线、爪牙）的工作范围。此评级的事物有三个结局:一、就地清剿；:二、放逐郊区；三、改变都市。<br> 此部分内容已完全遗失，急需补充和处理</p><p>司书专长<br> 司书训练（1）<br> 这项专长视为身份专长。通过专门的训练，司书已经逐步掌握使用书页的战斗方式<br> 你习得使用“决心+学识+书页+能量感知”进行攻击的方式，并附赠2级的书页专业，如当前专业等级已达上限，则改为额外获得1点书页检定上的加值。获得的书页攻击方式若无武器伤害，则具有基础的3L武器伤害。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',18)])])}const f=a(s,[["render",o]]);export{A as __pageData,f as default};
